const items = $input.all();
const rawData = items[0].json;
const transcripts = rawData && rawData.data && rawData.data.transcripts ? rawData.data.transcripts : [];
const now = new Date();
const yesterday = new Date(now.getTime() - 24 * 60 * 60 * 1000);
const recentMeetings = transcripts.filter(function(t) {
  const meetingDate = new Date(t.date);
  return meetingDate >= yesterday && meetingDate <= now;
});
if (recentMeetings.length === 0) {
  return [{ json: { hasMeetings: false, slackMessage: ':calendar: No new meeting recordings found in the past 24 hours.' } }];
}
const formattedItems = recentMeetings.map(function(meeting) {
  const title = meeting.title || 'Untitled Meeting';
  const date = meeting.date ? new Date(meeting.date).toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' }) : 'Unknown date';
  const duration = meeting.duration ? Math.round(meeting.duration / 60) + ' min' : 'Unknown duration';
  const overview = (meeting.summary && meeting.summary.overview) ? meeting.summary.overview : '_No summary available._';
  const actionItems = (meeting.summary && meeting.summary.action_items) ? meeting.summary.action_items : '_No action items recorded._';
  const lines = [
    '*:movie_camera: ' + title + '*',
    ':calendar: ' + date + '  :timer_clock: ' + duration,
    '',
    '*Summary*',
    overview,
    '',
    '*Action Items*',
    actionItems
  ];
  return { json: { hasMeetings: true, slackMessage: lines.join('
'), meetingTitle: title } };
});
return formattedItems;
